import hashlib
import hmac
import secrets
import time
from collections import Counter, defaultdict
from datetime import datetime
from typing import Dict, List, Optional
import json

from flask import Flask, request, jsonify
import numpy as np
from sklearn.ensemble import RandomForestClassifier
import pickle

app = Flask(__name__)

SECRET_KEY = secrets.token_hex(32)

class SecureDataLabelingSystem:
    def __init__(self):
        self.annotations = defaultdict(list)
        self.annotator_keys = {}
        self.annotator_reputation = defaultdict(lambda: 1.0)
        self.image_hashes = {}
        self.aggregated_labels = {}
        self.model = None
        self.label_history = defaultdict(list)
        self.annotator_timestamps = defaultdict(list)
        
    def register_annotator(self, annotator_id: str) -> str:
        api_key = secrets.token_urlsafe(32)
        key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        self.annotator_keys[annotator_id] = key_hash
        return api_key
    
    def verify_annotator(self, annotator_id: str, api_key: str) -> bool:
        if annotator_id not in self.annotator_keys:
            return False
        key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        return hmac.compare_digest(self.annotator_keys[annotator_id], key_hash)
    
    def compute_image_hash(self, image_data: bytes) -> str:
        return hashlib.sha256(image_data).hexdigest()
    
    def detect_label_flipping(self, annotator_id: str, image_id: str, label: str) -> bool:
        history_key = f"{annotator_id}:{image_id}"
        history = self.label_history[history_key]
        
        if len(history) > 0:
            if all(prev_label != label for prev_label in history):
                if len(history) >= 2:
                    return True
        
        timestamps = self.annotator_timestamps[annotator_id]
        current_time = time.time()
        timestamps.append(current_time)
        
        recent_timestamps = [ts for ts in timestamps if current_time - ts < 60]
        self.annotator_timestamps[annotator_id] = recent_timestamps
        
        if len(recent_timestamps) > 50:
            return True
        
        return False
    
    def add_annotation(self, annotator_id: str, image_id: str, label: str, 
                      image_data: bytes, api_key: str) -> Dict:
        if not self.verify_annotator(annotator_id, api_key):
            return {"error": "Invalid annotator credentials", "status": "rejected"}
        
        image_hash = self.compute_image_hash(image_data)
        
        if image_id in self.image_hashes:
            if self.image_hashes[image_id] != image_hash:
                return {"error": "Image hash mismatch - potential tampering", "status": "rejected"}
        else:
            self.image_hashes[image_id] = image_hash
        
        if self.detect_label_flipping(annotator_id, image_id, label):
            self.annotator_reputation[annotator_id] *= 0.5
            return {"error": "Label flipping detected", "status": "rejected"}
        
        history_key = f"{annotator_id}:{image_id}"
        self.label_history[history_key].append(label)
        
        annotation_signature = hmac.new(
            SECRET_KEY.encode(),
            f"{annotator_id}:{image_id}:{label}:{time.time()}".encode(),
            hashlib.sha256
        ).hexdigest()
        
        annotation_record = {
            "annotator_id": annotator_id,
            "label": label,
            "timestamp": datetime.now().isoformat(),
            "signature": annotation_signature,
            "reputation": self.annotator_reputation[annotator_id]
        }
        
        self.annotations[image_id].append(annotation_record)
        
        return {
            "status": "accepted",
            "image_id": image_id,
            "signature": annotation_signature
        }
    
    def aggregate_labels(self, image_id: str) -> Optional[str]:
        if image_id not in self.annotations:
            return None
        
        annotations = self.annotations[image_id]
        
        if len(annotations) < 3:
            return None
        
        weighted_votes = defaultdict(float)
        for ann in annotations:
            label = ann["label"]
            reputation = ann["reputation"]
            weighted_votes[label] += reputation
        
        if not weighted_votes:
            return None
        
        aggregated_label = max(weighted_votes.items(), key=lambda x: x[1])[0]
        
        self.aggregated_labels[image_id] = aggregated_label
        
        for ann in annotations:
            if ann["label"] == aggregated_label:
                self.annotator_reputation[ann["annotator_id"]] *= 1.1
            else:
                self.annotator_reputation[ann["annotator_id"]] *= 0.95
        
        return aggregated_label
    
    def get_training_data(self) -> tuple:
        X = []
        y = []
        
        for image_id, label in self.aggregated_labels.items():
            feature_vector = self._extract_features(image_id)
            if feature_vector is not None:
                X.append(feature_vector)
                y.append(label)
        
        return np.array(X), np.array(y)
    
    def _extract_features(self, image_id: str) -> Optional[List[float]]:
        if image_id not in self.image_hashes:
            return None
        
        hash_bytes = bytes.fromhex(self.image_hashes[image_id])
        features = [float(b) / 255.0 for b in hash_bytes[:32]]
        
        return features
    
    def train_model(self) -> Dict:
        X, y = self.get_training_data()
        
        if len(X) < 10:
            return {"error": "Insufficient training data", "status": "failed"}
        
        self.model = RandomForestClassifier(n_estimators=100, random_state=42)
        self.model.fit(X, y)
        
        return {
            "status": "success",
            "samples_trained": len(X),
            "unique_labels": len(set(y))
        }
    
    def predict(self, image_id: str) -> Optional[str]:
        if self.model is None:
            return None
        
        features = self._extract_features(image_id)
        if features is None:
            return None
        
        prediction = self.model.predict([features])[0]
        return prediction
    
    def get_annotator_stats(self, annotator_id: str) -> Dict:
        total_annotations = sum(
            1 for anns in self.annotations.values()
            for ann in anns if ann["annotator_id"] == annotator_id
        )
        
        return {
            "annotator_id": annotator_id,
            "total_annotations": total_annotations,
            "reputation": self.annotator_reputation[annotator_id]
        }

labeling_system = SecureDataLabelingSystem()

@app.route('/register', methods=['POST'])
def register_annotator():
    data = request.json
    annotator_id = data.get('annotator_id')
    
    if not annotator_id:
        return jsonify({"error": "annotator_id required"}), 400
    
    api_key = labeling_system.register_annotator(annotator_id)
    return jsonify({"annotator_id": annotator_id, "api_key": api_key}), 201

@app.route('/annotate', methods=['POST'])
def add_annotation():
    annotator_id = request.form.get('annotator_id')
    image_id = request.form.get('image_id')
    label = request.form.get('label')
    api_key = request.form.get('api_key')
    
    if 'image' not in request.files:
        return jsonify({"error": "image file required"}), 400
    
    image_file = request.files['image']
    image_data = image_file.read()
    
    result = labeling_system.add_annotation(
        annotator_id, image_id, label, image_data, api_key
    )
    
    if "error" in result:
        return jsonify(result), 403
    
    return jsonify(result), 200

@app.route('/aggregate/<image_id>', methods=['POST'])
def aggregate_labels(image_id):
    label = labeling_system.aggregate_labels(image_id)
    
    if label is None:
        return jsonify({"error": "Insufficient annotations"}), 400
    
    return jsonify({"image_id": image_id, "aggregated_label": label}), 200

@app.route('/train', methods=['POST'])
def train_model():
    result = labeling_system.train_model()
    
    if "error" in result:
        return jsonify(result), 400
    
    return jsonify(result), 200

@app.route('/predict/<image_id>', methods=['GET'])
def predict(image_id):
    prediction = labeling_system.predict(image_id)
    
    if prediction is None:
        return jsonify({"error": "Cannot make prediction"}), 400
    
    return jsonify({"image_id": image_id, "prediction": prediction}), 200

@app.route('/stats/<annotator_id>', methods=['GET'])
def get_stats(annotator_id):
    stats = labeling_system.get_annotator_stats(annotator_id)
    return jsonify(stats), 200

@app.route('/annotations/<image_id>', methods=['GET'])
def get_annotations(image_id):
    annotations = labeling_system.annotations.get(image_id, [])
    return jsonify({
        "image_id": image_id,
        "annotations": annotations,
        "count": len(annotations)
    }), 200

